// Makes the phone's hardware/gesture back button close whatever modal,
// sheet, or panel is currently open instead of exiting/backgrounding the
// whole app. Call it with the "is this open?" boolean and its close
// handler — while open it traps one entry in the browser history so the
// back button fires `onClose` instead of leaving the app; if the modal is
// closed normally (e.g. tapping X) it cleans that trapped entry back up.
function useBackClose(isOpen, onClose) {
  const closedByBack = React.useRef(false);
  const onCloseRef = React.useRef(onClose);
  onCloseRef.current = onClose;

  React.useEffect(() => {
    if (!isOpen) return undefined;

    closedByBack.current = false;
    window.history.pushState({ appOverlay: true }, "");

    const handlePopState = () => {
      closedByBack.current = true;
      onCloseRef.current();
    };

    window.addEventListener("popstate", handlePopState);

    return () => {
      window.removeEventListener("popstate", handlePopState);
      if (!closedByBack.current) {
        window.history.back();
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen]);
}
