/* ------------------------------------------------------------------ */
/*  Backend API — talks to the same Pancity NestJS + MongoDB backend    */
/*  used by PancityDashboard.jsx (the admin app). Set                   */
/*  REACT_APP_API_BASE (CodeSandbox env var) to your backend URL,       */
/*  e.g. "https://<your-backend-sandbox-id>-3000.csb.app/api"           */
/* ------------------------------------------------------------------ */
const API_BASE = (typeof process !== "undefined" && process.env && process.env.REACT_APP_API_BASE) || "http://localhost:3000/api";

function getUserToken() {
  return localStorage.getItem("pancity_user_token") || null;
}
function setUserToken(token) {
  if (token) localStorage.setItem("pancity_user_token", token);
  else localStorage.removeItem("pancity_user_token");
}

async function apiRequest(path, { method = "GET", body, auth = true } = {}) {
  const headers = { "Content-Type": "application/json" };
  if (auth) {
    const token = getUserToken();
    if (token) headers.Authorization = `Bearer ${token}`;
  }
  const res = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body ? JSON.stringify(body) : undefined,
  });
  const data = await res.json().catch(() => null);
  if (!res.ok) throw new Error((data && data.message) || `Request failed (${res.status})`);
  return data;
}

