// Builds the {network, target} pair the backend needs from whichever form
// fields this particular service happens to use.
function getPurchaseNetworkAndTarget(service, form) {
  switch (service) {
    case "Mobile Data":
    case "Airtime":
    case "Airtime 2 Cash":
      return { network: form.network || "", target: form.phone || "" };
    case "Cable TV":
      return { network: form.cableProvider || "", target: form.smartcard || "" };
    case "Electricity":
      return { network: form.disco || "", target: form.meter || "" };
    case "Exam Pin":
      return { network: form.examType || "", target: form.phone || "N/A" };
    default:
      return { network: "", target: "" };
  }
}

