function detectNetwork(phone) {
  let p = (phone || "").replace(/\s/g, "");
  if (p.startsWith("+234")) p = "0" + p.slice(4);
  else if (p.startsWith("234")) p = "0" + p.slice(3);
  const prefix = p.slice(0, 4);
  for (const [network, prefixes] of Object.entries(NETWORK_PREFIXES)) {
    if (prefixes.includes(prefix)) return network;
  }
  return null;
}

// Attempts to trigger the device's real fingerprint/Face ID prompt via WebAuthn.
// Returns "success" if the user verifies, "declined" if they cancel/fail verification,
// or "unsupported" if this device/browser can't do platform biometrics (e.g. desktop
// without Touch ID/Windows Hello, or an unsupported/sandboxed browser context).
async function tryDeviceBiometric() {
  try {
    if (
      typeof window === "undefined" ||
      !window.PublicKeyCredential ||
      !navigator.credentials ||
      !PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable
    ) {
      return "unsupported";
    }

    const available = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
    if (!available) return "unsupported";

    const challenge = new Uint8Array(32);
    window.crypto.getRandomValues(challenge);
    const userId = new Uint8Array(16);
    window.crypto.getRandomValues(userId);

    await navigator.credentials.create({
      publicKey: {
        challenge,
        rp: { name: "Pancity" },
        user: { id: userId, name: "pancity-user", displayName: "Pancity User" },
        pubKeyCredParams: [
          { type: "public-key", alg: -7 },
          { type: "public-key", alg: -257 },
        ],
        authenticatorSelection: { authenticatorAttachment: "platform", userVerification: "required" },
        timeout: 60000,
        attestation: "none",
      },
    });
    return "success";
  } catch (err) {
    return "declined";
  }
}

